FNePyStructBase* NePyStructPropGet_Rotator(const FStructProperty* InStructProp, const void* InBuffer)
{
	PyTypeObject* PyType = &FNePyStructType_Rotator;
	FNePyStruct_Rotator* PyObj = (FNePyStruct_Rotator*)PyType->tp_alloc(PyType, 0);
#if NEPY_ENABLE_STRUCT_DEEP_ACCESS
	PyObj->Value = (FRotator*)InBuffer;
	PyObj->SelfCreatedValue = false;
#else
	PyObj->Value = (FRotator*)FMemory::Malloc(sizeof(FRotator), alignof(FRotator));
	NePyBase::EnsureCopyToStructSafely<FRotator>(InStructProp, PyObj->Value);
	InStructProp->Struct->CopyScriptStruct(PyObj->Value, InBuffer);
	PyObj->SelfCreatedValue = true;
#endif
	PyObj->PyOuter = nullptr;
	return PyObj;
}

